uint16_t RFID_CARD_Enter;
uint16_t RFID_CARD_EXIT;

uint8_t pass[3] ={0};

unsigned char Available_Slots='3';
uint8_t Search_Done = 0;

volatile uint8_t enterFlag=0;
volatile uint8_t ExitFlag=0;

volatile uint8_t PIR1=0;
volatile uint8_t PIR2=0;


#define MAX_IDS 3
#define ID_LENGTH 3

uint8_t Admin_IDs[MAX_IDS][ID_LENGTH] = {0};  // array to store IDs

void RFID_CARD_Enter_CallBack(void);
