/* Key mapping for 3x4 keypad */
const uint8_t KeyPad_Keys[4][3] =
{
    {'#','0','*'},   // Row 0
    {'9','8','7'},   // Row 1
    {'6','5','4'},   // Row 2
    {'3','2','1'}    // Row 3
};

/* Keypad object */
KeyPad_ConfigType Keypad3x4 =
{
    .Rows = 4,
    .Cols = 3,

    .RowPins =
    {
        { PORTB, GPIO_PIN0 },
        { PORTB, GPIO_PIN1 },
        { PORTB, GPIO_PIN3 },
        { PORTB, GPIO_PIN4 }
    },

    .ColPins =
    {
        { PORTB, GPIO_PIN5 },
        { PORTB, GPIO_PIN6 },
        { PORTB, GPIO_PIN7 }
    },

    .KeyMap = KeyPad_Keys
};
int main(void)
{

	RCC_GPIOA_CLK_EN();
	RCC_GPIOB_CLK_EN();
	RCC_AFIO_CLK_EN();
	KeyPad_Init(&Keypad3x4);

	Timer2_init();
	Servo1_Entry_Gate_Init();
	Servo2_Exit_Gate_Init();
	//==========================UART1 INIT=============================

	UARTpins1.BaudRate=UART_BaudRate_115200;
	UARTpins1.Payload_Length=UART_Payload_Length_8B;
	UARTpins1.HW_FlowCTL=UART_HW_FlowCTL_NONE;
	UARTpins1.IRQ_Enable= UART_IRQ_Enable_RXNE;
	UARTpins1.Mode=UART_Mode_TX_RX;
	UARTpins1.Parity=UART_Parity_NONE;
	UARTpins1.StopBits=UART_StopBits_1;
	UARTpins1.UART=UART1;
	UARTpins1.p_IRQ_CallBack=RFID_CARD_Enter_CallBack;
	UART_Init(&UARTpins1);

	//==========================UART2 INIT=============================

	UARTpins2.BaudRate=UART_BaudRate_115200;
	UARTpins2.Payload_Length=UART_Payload_Length_8B;
	UARTpins2.HW_FlowCTL=UART_HW_FlowCTL_NONE;
	UARTpins2.IRQ_Enable=UART_IRQ_Enable_RXNE;
	UARTpins2.Mode=UART_Mode_TX_RX;
	UARTpins2.Parity=UART_Parity_NONE;
	UARTpins2.StopBits=UART_StopBits_1;
	UARTpins2.UART=UART2;
	UARTpins2.p_IRQ_CallBack=RFID_CARD_EXIT_CallBack;
	UART_Init(&UARTpins2);

	Lcd_Init(&LCD1);
	Lcd_Init(&LCD2);

	LEDs_Init();
	PIRs_Iint();


	/*==========Enter IDs To Store In Array Pass==========*/
	 Store_IDs_From_Admin();

	/*Dash Bord LCD*/
	LCD_Welcome();
	dms(200);
	LCD_Display_Empty_Slots();

	while(1)
	{
		for(uint8_t i = 0; i < ID_LENGTH; i++)
		{
		    UART_Receive_Data(&UARTpins1, &RFID_CARD_Enter);   // Receive 1 byte
		    pass[i] = (uint8_t)RFID_CARD_Enter;               // Store in pass array
		}

		UART_Receive_Data(&UARTpins2,&RFID_CARD_EXIT);
		if(enterFlag)
		{
			enterFlag=0;
			Entring_Fun();
		}
		if(ExitFlag)
		{
			ExitFlag=0;
			Exit_Fun();
		}

	}

	return 0;
}


/*Call Back For UART*/
void RFID_CARD_Enter_CallBack(void)
{
	UART_Send_Data(&UARTpins1,&RFID_CARD_Enter);
	enterFlag=1;
}

void RFID_CARD_EXIT_CallBack(void)
{
	UART_Send_Data(&UARTpins2,&RFID_CARD_EXIT);
	ExitFlag=1;
}



void LCD_Welcome(void)
{
    /* Clear display */
    Lcd_SendCommand(&LCD1, 0x01);

    /* Set cursor to row 0, column 0 */
    Lcd_SetCursor(&LCD1, 0, 0);
    Lcd_SendString(&LCD1, (uint8_t*)"Welcome in");

    /* Set cursor to row 1, column 0 */
    Lcd_SetCursor(&LCD1, 1, 0);
    Lcd_SendString(&LCD1, (uint8_t*)"Tanta Parking");
}

void LCD_Display_Empty_Slots(void)
{
    /* Clear display */
    Lcd_SendCommand(&LCD1, 0x01);

    /* First line */
    Lcd_SetCursor(&LCD1, 0, 0);
    Lcd_SendString(&LCD1, (uint8_t*)"Empty Slots=");

    /* Print number at column 13 */
    Lcd_SetCursor(&LCD1, 0, 13);
    Lcd_SendChar(&LCD1, Available_Slots);
}

