void PIRs_Iint(void)
{
	//PIR1 A7
	GPIO_Config_Pin_t PinCinfg;
	PinCinfg.PORTx=PORTA;
	PinCinfg.Pin_Number=GPIO_PIN7;
	PinCinfg.mode = GPIO_MODE_Input_FLO;
	GPIO_InitPin(&PinCinfg);

	//PIR2 A1
	PinCinfg.PORTx=PORTA;
	PinCinfg.Pin_Number=GPIO_PIN1;
	PinCinfg.mode = GPIO_MODE_Input_FLO;
	GPIO_InitPin(&PinCinfg);

	GPIO_WritePin(PORTA, GPIO_PIN0, 1); //make A0 ground
	GPIO_WritePin(PORTA, GPIO_PIN11, 1); //make A11 ground

}



void Store_IDs_From_Admin(void)
{
    uint8_t i, j, key;

    for(i=0; i<MAX_IDS; i++)
    {
        // Clear LCD before each ID input
        Lcd_SendCommand(&LCD2, 0x01);
        Lcd_SetCursor(&LCD2, 0, 0);
        Lcd_SendString(&LCD2, (uint8_t*)"Enter ID #");
        Lcd_SendChar(&LCD2, '1'+i); // display ID number (1,2,3)
        Lcd_SetCursor(&LCD2, 1, 0);
        Lcd_SendString(&LCD2, (uint8_t*)"ID: ");

        j = 0;
        while(j < ID_LENGTH)
        {
            // Wait until a key is pressed
            if(KeyPad_GetKey(&Keypad3x4, &key) == E_OK)
            {
                if(key >= '0' && key <= '9')
                {
                    // Display key on LCD
                    Lcd_SendChar(&LCD2, key);
                    // Store in array
                    Admin_IDs[i][j] = key;
                    j++;
                    // Debounce using Timer2
                    dms(30); // 30 ms debounce
                }
                else if(key == '#')
                {
                    // Finish this ID early if user presses #
                    break;
                }
                else if(key == '*')
                {
                    // Optional: clear last digit
                    if(j > 0)
                    {
                        j--;
                        // Move cursor back and clear character
                        Lcd_SetCursor(&LCD2, 1, 4 + j);
                        Lcd_SendChar(&LCD2, ' ');
                        Lcd_SetCursor(&LCD2, 1, 4 + j);
                    }
                }
            }
        }
    }

    // After all IDs entered, optional: show confirmation
    Lcd_SendCommand(&LCD2, 0x01);
    Lcd_SetCursor(&LCD2, 0, 0);
    Lcd_SendString(&LCD2, (uint8_t*)"IDs Saved!");
    dms(1000); // 1 second delay
}
void Entring_Fun(void)
{
	if(Available_Slots == '0')
	{
		Lcd_SetCursor(&LCD1,1,0);
		Lcd_SendString(&LCD1,(uint8_t*)"Parking is Full");
		dms(1000);
		return ;
	}

	//Search about ID in array of Pass

	for(uint8_t i = 0; i < MAX_IDS; i++)
	{
	    uint8_t match = 1; // Assume match
	    for(uint8_t j = 0; j < ID_LENGTH; j++)
	    {
	        if(Admin_IDs[i][j] != pass[j])
	        {
	            match = 0; // Not a match
	            break;
	        }
	    }
	    if(match)
	    {
	        Search_Done = 1; // ID found
	        break; // Exit loop
	    }
	}
	// Search_Done = 1; // ID found
	/*=====================Enter gate=====================*/
	if(Search_Done==1)
	{
		Search_Done=0;
		Led_ON(&green_led);
		Servo1_Entry_Gate(UP);
		GPIO_ReadPin(PORTA,GPIO_PIN7,&PIR2);
		while(!PIR2){GPIO_ReadPin(PORTA,GPIO_PIN7,&PIR2);}
		Servo1_Entry_Gate(Down);
		Led_OFF(&green_led);
		Available_Slots--;


	}
	else
	{
		Lcd_SetCursor(&LCD1,0,0);
		Lcd_SendString(&LCD1,(uint8_t*)"Worng ID :( ");
		Lcd_SetCursor(&LCD1,1,0);
		Lcd_SendString(&LCD1,(uint8_t*)"tray again ");
		dms(2000);
		return ;
	}
}

void Exit_Fun(void)
{
	Servo2_Exit_Gate(UP);
	GPIO_ReadPin(PORTA,GPIO_PIN1,&PIR1);
	while(!PIR1){GPIO_ReadPin(PORTA,GPIO_PIN1,&PIR1);}
	Servo2_Exit_Gate(Down);
	Available_Slots++;

}

